/**
 * Builds the browser bundle — a self-contained IIFE containing React, ReactDOM,
 * the React shell framework, and all built-in scene component Component functions.
 *
 * Output: src/browser/_generated-browser-bundle.ts
 *
 * This file is imported by the renderer at build time (via tsup) and embedded
 * as a string constant in the final renderer package.
 */

import { build } from "esbuild";
import { writeFileSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = resolve(__dirname, "../../..");

const result = await build({
  entryPoints: [resolve(__dirname, "../src/browser/browser-entry.tsx")],
  bundle: true,
  format: "iife",
  platform: "browser",
  target: "es2020",
  minify: false,
  write: false,
  jsx: "automatic",
  jsxImportSource: "react",
  alias: {
    "@lyric-video-maker/core": resolve(root, "packages/core/src/index.ts"),
    "@lyric-video-maker/plugin-base": resolve(root, "packages/plugin-base/src/index.ts"),
    "~scene-registry": resolve(root, "packages/scene-registry/src"),
  },
  define: {
    "process.env.NODE_ENV": '"production"',
  },
  logLevel: "warning",
});

const bundleCode = result.outputFiles[0].text;

// Escape backticks and ${ for template literal embedding
const escaped = bundleCode
  .replace(/\\/g, "\\\\")
  .replace(/`/g, "\\`")
  .replace(/\$\{/g, "\\${");

const output = `// THIS FILE IS AUTO-GENERATED by scripts/build-browser-bundle.mjs — DO NOT EDIT.
export const BROWSER_BUNDLE_SOURCE = \`${escaped}\`;
`;

const outputPath = resolve(__dirname, "../src/browser/_generated-browser-bundle.ts");
writeFileSync(outputPath, output, "utf-8");

const sizeKb = Math.round(bundleCode.length / 1024);
console.log(`Browser bundle built: ${sizeKb}KB → ${outputPath}`);
